/**
 * Screenshot for /unprivate-blabla: a blablalink.com profile card with the
 * padlock (privacy) icon highlighted in the top-right.
 *
 * It's stored inline as base64 on purpose. The bot is built with plain `tsc`
 * (no step that copies image files into `dist/`), and Discord CDN links expire,
 * so embedding the bytes in a compiled module is the simplest way to make the
 * screenshot **permanent** — it ships everywhere the code ships, with no
 * external URL or database row that can rot.
 *
 * To replace the screenshot: base64-encode the new PNG and paste it below
 * (PowerShell: `[Convert]::ToBase64String([IO.File]::ReadAllBytes("shot.png"))`).
 * An empty string is allowed — the command simply posts the text steps without
 * the image until real bytes are added.
 */
const BLABLA_PADLOCK_BASE64 =
  '';

export const blablaPadlockPng = Buffer.from(BLABLA_PADLOCK_BASE64, 'base64');
